import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v14 (Nonprofits & Donation Organizations) ===');

w('profiles_v14','salvation-army',{"brand_name":"Salvation Army","brand_slug":"salvation-army","parent_company":"The Salvation Army","ultimate_parent":"General of The Salvation Army","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"THE SALVATION ARMY HAS DOCUMENTED POLICIES REQUIRING LGBT PEOPLE TO RENOUNCE THEIR SEXUALITY TO RECEIVE SERVICES — IT TAKES $2 BILLION A YEAR IN GOVERNMENT CONTRACTS — AND ITS INTERNATIONAL LEADER ONCE SAID HOMOSEXUALITY DESERVES DEATH","executive_summary":"The Salvation Army is a Christian organization operating as an international church and social services provider, with annual revenue of approximately $4 billion — including approximately $2 billion in US government contracts and grants. It operates homeless shelters, food pantries, disaster relief, and rehabilitation programs. Its documented anti-LGBTQ policies have been the subject of sustained criticism and organized boycotts. A 2012 interview with Salvation Army Australia's media director confirmed that, in his interpretation, the organization's theology holds that homosexuality warrants the death penalty — a statement the Salvation Army subsequently repudiated. The organization has documented policies requiring LGBTQ individuals seeking services at some of its shelters and programs to renounce their sexual orientation or face denial of services. Multiple investigations have documented that transgender individuals have been denied shelter access consistent with their gender identity at Salvation Army facilities.","verdict_tags":["2b_government_contracts_lgbtq_discrimination","australia_director_homosexuality_death_statement","transgender_shelter_denial_documented","boycott_red_kettle_organized","lgbtq_renounce_sexuality_services_condition","4b_annual_revenue_christian_organization","rehabilitation_program_religious_conditions","2_billion_government_funded_lgbtq_discrimination"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"The Salvation Army employs approximately 27,000 people in the US and hundreds of thousands globally, with a significant volunteer workforce. Its rehabilitation programs — Adult Rehabilitation Centers — have been documented as using program participants as labor in thrift stores for minimal compensation while the thrift stores generate significant revenue for the organization.","flags":["adult_rehabilitation_centers_participant_labor_thrift","thrift_store_revenue_participant_minimal_compensation"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against the Salvation Army have been identified.","flags":[],"sources":[]},"political":{"summary":"The Salvation Army's official positions on homosexuality — that it is 'a departure from God's will' requiring 'redemptive grace' — have been consistent since its founding in Victorian England. These positions have translated into documented service policies: LGBTQ individuals seeking services at some Salvation Army facilities have been required to renounce homosexual relationships as a condition of service; transgender individuals have been documented as denied shelter consistent with their gender identity. The Salvation Army has lobbied against LGBTQ non-discrimination laws in multiple jurisdictions, arguing that requiring it to serve LGBTQ people without condition violates its religious freedom.","flags":["official_homosexuality_departure_gods_will_position","services_conditioned_renouncing_homosexuality","transgender_shelter_denial_documented","lgbtq_non_discrimination_law_opposition_lobbying"],"sources":[]},"legal":{"summary":"The Salvation Army's receipt of approximately $2 billion annually in US government contracts and grants — including from federal, state, and local governments — while maintaining documented discriminatory service policies has generated legal challenges under civil rights law. Multiple cities have reduced or eliminated Salvation Army contracts following documented discrimination against LGBTQ recipients. San Francisco cut $3.5 million in Salvation Army contracts in 2003 after the organization refused to extend employee benefits to domestic partners. Multiple government contractors have anti-discrimination requirements that the Salvation Army has sought religious exemptions from.","flags":["2b_government_contracts_with_discrimination","san_francisco_3_5m_cut_2003","religious_exemption_sought_contractor_requirements","multiple_cities_reduced_contracts"],"sources":[]},"tax":{"summary":"The Salvation Army is registered as a religious organization and church — giving it broader tax exemptions than standard nonprofits, including the ability to receive tax-deductible donations while not filing Form 990 for its church activities. Its social services arms file Form 990. The approximately $2 billion in annual government contracts represents taxpayer funds flowing to an organization with documented discriminatory service policies.","flags":["church_registration_broader_exemption","2b_taxpayer_funds_discriminatory_policies","social_services_form_990_filed"],"sources":[]},"executives":{"summary":"General LyndonBöhmer leads the Salvation Army internationally. The international General is elected by a High Council. The Salvation Army's leadership is embedded in its military-style hierarchy — officers rather than pastors. Commissioner Kenneth Hodder leads the USA Western Territory. The 2012 incident in which Salvation Army Australia's media director said homosexuals 'deserve death' — per the Bible — before retracting the statement represents the most documented leadership statement connecting the organization's theology to violence.","flags":["australia_director_homosexuals_deserve_death_2012","statement_retracted","military_hierarchy_officers","hodder_usa_western_territory"],"sources":[]},"connections":{"summary":"The Salvation Army's red kettle Christmas campaign is one of the most recognized charitable fundraising activities in America — generating approximately $2 billion annually from public donations. Organized boycotts of the red kettle campaign have been documented since at least 2012, when the Australia homosexuality-death statement went viral. The organization's network of thrift stores — Family Stores — competes with Goodwill in many markets.","flags":["red_kettle_2b_annual_recognized","organized_boycott_2012_ongoing","family_stores_thrift_competition_goodwill"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"LGBTQ advocates and investigative journalists have documented specific cases in which Salvation Army shelters denied services to LGBTQ individuals — requiring them to pray, attend services, or renounce relationships as conditions of shelter access. The Salvation Army has disputed many individual cases while maintaining its official theological position. Transgender individuals have documented specific incidents of being denied shelter consistent with gender identity at Salvation Army facilities.","flags":["specific_cases_services_denied_documented","prayer_services_renounce_relationship_conditions_documented","transgender_gender_identity_denial_documented"],"sources":[]},"health_record":{"summary":"The denial of emergency shelter services to LGBTQ individuals — particularly transgender individuals — has documented life safety consequences in jurisdictions where the Salvation Army is a primary shelter provider. LGBTQ youth who are homeless at higher rates than non-LGBTQ youth have been documented as avoiding Salvation Army services due to documented discrimination, reducing their access to emergency services.","flags":["emergency_shelter_denial_life_safety","lgbtq_youth_avoiding_services_access_reduction","transgender_primary_shelter_denial_documented"],"sources":[]},"alternatives":{"cheaper":["Local community shelters without religious conditions on service","Secular food banks and community fridges without religious programming requirements"],"healthier":["LGBTQ-affirming shelters — National Center for Transgender Equality maintains a resource list","Secular emergency services without documented LGBTQ service conditions"],"diy":["Before donating to the red kettle: check whether your local Salvation Army has documented LGBTQ service policies","Local Community Action Agencies provide emergency services without documented religious conditions"]},"timeline":[{"year":1865,"event":"William Booth founds Salvation Army in London's East End; Victorian-era theology shapes its positions on sexuality","severity":"neutral","source_url":""},{"year":2001,"event":"Multiple cities including San Francisco document Salvation Army refusing domestic partner benefits to employees; contracts cut","severity":"high","source_url":""},{"year":2012,"event":"Salvation Army Australia media director says homosexuals 'deserve death' per the Bible in interview; statement retracted after global outrage","severity":"critical","source_url":""},{"year":2017,"event":"Multiple transgender individuals document being denied shelter consistent with gender identity at Salvation Army facilities","severity":"critical","source_url":""},{"year":2019,"event":"Salvation Army 'Do Homosexuals Deserve to Die?' FAQ document discovered on website; removed after media coverage","severity":"critical","source_url":""}],"community_impact":{"displacement":"LGBTQ individuals — particularly homeless LGBTQ youth and transgender individuals — who are denied Salvation Army services in communities where it is a primary emergency shelter provider face documented displacement with limited alternatives. The Salvation Army's $2 billion in government contracts funds services that, in documented cases, have been conditioned on religious compliance.","price_illusion":"The red kettle and holiday donation campaigns present the Salvation Army as a straightforward emergency services charity. The $2 billion in government contracts — and the documented service conditions attached to some Salvation Army programs — represent public funding of an organization that has official policies treating LGBTQ people as requiring redemption.","tax_math":"The Salvation Army receives approximately $2 billion annually in US government contracts and approximately $2 billion in public donations — $4 billion total — as a tax-exempt religious organization whose official theology characterizes homosexuality as a departure from God's will. Donors receive tax deductions for contributing to an organization with documented discriminatory service policies.","wealth_velocity":"The Salvation Army's $4 billion annual US revenue funds an international organization with documented theological commitments that translate into documented service discrimination. The Adult Rehabilitation Centers' use of program participants as thrift store labor — for minimal compensation while the stores generate significant revenue — represents a labor model worth scrutinizing."},"cost_absorption":{"who_benefited":[{"group":"Salvation Army","how":"$2B in government contracts plus $2B in public donations; tax-exempt status as church; red kettle recognition enables continued fundraising despite documented discrimination"}],"who_paid":[{"group":"LGBTQ individuals denied services","how":"Emergency shelter denied; services conditioned on renouncing relationships; transgender individuals denied gender-consistent shelter; in communities where Salvation Army is primary provider, no alternative exists"}],"the_gap":"The Salvation Army takes $2 billion a year in US government contracts. Its official theology says homosexuality is a departure from God's will. Its Australia media director said homosexuals deserve death in 2012. The statement was retracted. A FAQ document on their website asking 'Do Homosexuals Deserve to Die?' was discovered and removed. Transgender people have been denied shelter consistent with their gender identity at documented specific locations. The red kettle raises another $2 billion. Donations are tax-deductible."}});

w('profiles_v14','goodwill-industries',{"brand_name":"Goodwill Industries","brand_slug":"goodwill-industries","parent_company":"Goodwill Industries International","ultimate_parent":"Goodwill Industries International","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"GOODWILL LEGALLY PAYS SOME DISABLED WORKERS $0.22 PER HOUR USING A FEDERAL SUBMINIMUM WAGE EXEMPTION — WHILE ITS LOCAL CEOs MAKE $400,000-$700,000 — AND SELLS DONATED GOODS FOR PROFIT THAT MOSTLY DOESN'T GO TO THOSE WORKERS","executive_summary":"Goodwill Industries International is a network of approximately 157 independent local Goodwill organizations operating approximately 3,300 thrift stores across the United States and Canada, collectively generating over $6 billion in annual revenue. Goodwill is one of America's most recognized charitable brands — donations of used clothing and household goods are a routine part of American life. Under Section 14(c) of the Fair Labor Standards Act, Goodwill and other nonprofits are permitted to pay workers with disabilities at rates below the federal minimum wage — as low as $0.22 per hour in documented cases. Multiple Goodwill affiliates have paid disabled workers subminimum wages while their CEOs received compensation of $400,000-$700,000 annually. The combination — disabled workers paid cents per hour while affiliated CEOs earn hundreds of thousands — has been documented by disability rights advocates and journalists as one of the most egregious compensation disparities in the nonprofit sector.","verdict_tags":["section_14c_subminimum_wage_0_22_per_hour","ceo_400k_700k_while_workers_cents","6b_annual_revenue_recognized_brand","157_independent_local_affiliates","donated_goods_resold_revenue","disability_rights_advocacy_opposition","congressional_hearings_14c_documented","goodwill_international_no_direct_control_affiliates"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Section 14(c) of the Fair Labor Standards Act — enacted in 1938 — allows employers who obtain special certificates from the Department of Labor to pay workers with disabilities at rates commensurate with their productivity rather than minimum wage. Goodwill has been one of the largest users of these certificates. Documented cases: Goodwill of Southern Arizona paid some workers $0.22 per hour while its CEO received $729,000 annually. Multiple Goodwill affiliates paying subminimum wages while maintaining CEO compensation in the hundreds of thousands have been documented by NBC News investigations. Goodwill International maintains it does not control affiliates' wage practices.","flags":["0_22_per_hour_documented_southern_arizona","ceo_729k_southern_arizona","14c_certificates_goodwill_largest_users","goodwill_international_no_affiliate_control","multiple_affiliates_documented_nbc"],"sources":["https://www.nbcnews.com/feature/in-plain-sight/goodwill-pays-disabled-workers-pennies-hour-its-ceos-pull-n286081"]},"environmental":{"summary":"Goodwill's thrift store model diverts millions of tons of used goods from landfills annually — a genuine environmental benefit. The organization has documented sustainability commitments around textile recycling. No major environmental enforcement actions have been identified.","flags":["millions_tons_diverted_landfill_genuine_benefit","textile_recycling_documented"],"sources":[]},"political":{"summary":"Goodwill Industries International has lobbied against the elimination of Section 14(c) — the subminimum wage provision it uses for disabled workers. Disability rights organizations — including the National Federation of the Blind, the National Disability Rights Network, and ADAPT — have documented opposition to 14(c) and have targeted Goodwill as its most visible beneficiary. Multiple states have passed or are considering laws eliminating subminimum wages for disabled workers. Goodwill has argued that eliminating 14(c) would result in employers being unable to hire workers with the most significant disabilities.","flags":["14c_lobbying_documented","national_federation_blind_opposition","adapt_target_goodwill","states_eliminating_subminimum_wage","goodwill_argument_employment_impact"],"sources":[]},"legal":{"summary":"Section 14(c) is legal under federal law — Goodwill's subminimum wage payments are authorized by DOL certificates. The legal controversy is whether 14(c) should continue to exist rather than whether Goodwill has violated existing law. Congressional hearings on 14(c) have featured both Goodwill defense of the practice and disability rights advocates' testimony against it. No major criminal enforcement actions against Goodwill have been identified.","flags":["14c_legal_dol_certified","14c_elimination_congressional_hearings","no_criminal_enforcement","legal_controversy_not_violations"],"sources":[]},"tax":{"summary":"Goodwill Industries International and its affiliated local organizations are 501(c)(3) public charities — donations are tax-deductible. Goodwill's revenue model — accepting donated goods and reselling them — generates significant revenue from donated items whose donors received charitable tax deductions. The extent to which this revenue funds services for disabled workers (vs. administrative costs and executive compensation) has been documented as variable across affiliates.","flags":["501c3_donations_deductible","donated_goods_resale_revenue_model","revenue_to_services_ratio_variable_affiliates"],"sources":[]},"executives":{"summary":"Steven Preston serves as CEO of Goodwill Industries International. Local affiliate CEOs are employed by independent boards and are not controlled by Goodwill International. The local affiliate CEO compensation disparities — $400,000-$729,000 annually at affiliates paying workers $0.22/hour — represent decisions made by independent local boards rather than Goodwill International. This organizational structure both enables local flexibility and limits central accountability.","flags":["preston_international_ceo","local_affiliate_independent_boards","local_compensation_disparity_not_international_controlled"],"sources":[]},"connections":{"summary":"Goodwill's thrift store network competes with Salvation Army Family Stores, Habitat for Humanity ReStores, and commercial thrift chains. Its charitable brand recognition is among the highest of any US nonprofit — the Goodwill name on a thrift store generates significant donation volume based on brand trust built over a century. The 14(c) issue connects Goodwill to the broader disability employment policy debate.","flags":["salvation_army_habitat_competition","century_brand_trust","14c_disability_employment_policy_debate"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Disability rights advocates have alleged that Goodwill's use of 14(c) is not primarily about enabling meaningful employment for workers with the most significant disabilities — as the program's defenders argue — but about accessing a legal labor arbitrage that allows Goodwill to staff its thrift store operations at dramatically below-market rates while generating significant revenue. Goodwill disputes this characterization and maintains that 14(c) workers receive training, rehabilitation services, and community integration that they would not receive in competitive employment.","flags":["labor_arbitrage_not_rehabilitation_alleged_advocates","goodwill_training_rehabilitation_community_integration_argument","14c_worker_outcome_debate"],"sources":[]},"health_record":{"summary":"No direct public health enforcement actions against Goodwill have been identified. The subminimum wage issue intersects with disability rights research documenting that segregated employment at subminimum wages is associated with worse life outcomes for disabled workers compared to supported competitive employment — a documented finding that disability rights organizations use to argue for 14(c) elimination.","flags":["segregated_subminimum_employment_worse_outcomes_documented","supported_competitive_employment_better_outcomes_documented"],"sources":[]},"alternatives":{"cheaper":["Local thrift stores operated by non-14(c) nonprofits","Habitat for Humanity ReStores — building materials and furniture; revenue funds Habitat homebuilding"],"healthier":["Thrift stores that do not use Section 14(c) subminimum wage provisions","Donating directly to organizations that employ disabled workers at minimum wage or above"],"diy":["Check whether your local Goodwill affiliate uses Section 14(c) — some affiliates have voluntarily eliminated the practice","The DOL maintains a database of 14(c) certificate holders — verify whether your local Goodwill holds one"]},"timeline":[{"year":1902,"event":"Edgar Helms founds Goodwill Industries in Boston as a social enterprise employing poor immigrants and people with disabilities","severity":"neutral","source_url":""},{"year":1938,"event":"Fair Labor Standards Act enacted; Section 14(c) subminimum wage provision included — allows paying disabled workers below minimum wage","severity":"high","source_url":""},{"year":2013,"event":"NBC News investigation documents Goodwill affiliates paying workers $0.22/hour while CEOs earn $700,000+; national attention","severity":"critical","source_url":"https://www.nbcnews.com/feature/in-plain-sight/goodwill-pays-disabled-workers-pennies-hour-its-ceos-pull-n286081"},{"year":2014,"event":"Congressional hearings on Section 14(c) elimination; Goodwill lobbies against; disability rights organizations testify in favor","severity":"critical","source_url":""},{"year":2023,"event":"Multiple states including Maryland and New Hampshire eliminate subminimum wages; Goodwill affiliates adjust practices in those states","severity":"high","source_url":""}],"community_impact":{"displacement":"Disabled workers paid subminimum wages at Goodwill affiliates — in some documented cases as little as $0.22/hour — receive wages insufficient to support independent living. The research consensus that supported competitive employment produces better outcomes for disabled workers suggests that 14(c) placements, while providing some employment, may not serve workers' long-term interests relative to alternatives.","price_illusion":"Goodwill donations are made with the understanding that proceeds fund employment programs for people with disabilities. The extent to which revenue goes to those programs — vs. executive compensation and administrative costs — varies by affiliate and is not transparently disclosed in Goodwill's brand marketing.","tax_math":"Goodwill receives donated goods for which donors claim charitable tax deductions. These goods are resold at full retail prices in thrift stores generating $6+ billion annually. The workers processing and selling these goods may legally be paid $0.22/hour under Section 14(c) while local CEOs earn $400,000-$729,000. The charitable tax deductions subsidize this revenue model.","wealth_velocity":"Goodwill's $6+ billion annual revenue is distributed across 157 independent affiliates. Local affiliate executives capture significant compensation from operations funded by donated goods and charitable tax deductions — while the workers whose employment constitutes Goodwill's charitable mission may earn subminimum wages."},"cost_absorption":{"who_benefited":[{"group":"Goodwill affiliate executives","how":"$400,000-$729,000 annual compensation at affiliates legally paying workers $0.22/hour; independent local boards without Goodwill International accountability"}],"who_paid":[{"group":"Disabled workers paid subminimum wages","how":"As little as $0.22/hour legally under Section 14(c); wages insufficient for independent living; CEO earns in one day what worker earns in years at subminimum rate"},{"group":"Donors who believed donations funded worker programs","how":"Donated goods generate $6B+ in revenue; donor intent is employment programs; portion captured by executive compensation"}],"the_gap":"Goodwill legally pays some disabled workers $0.22 an hour. Section 14(c) of the Fair Labor Standards Act allows this. A Goodwill affiliate CEO made $729,000 in the same year workers made $0.22 an hour. Goodwill International says it doesn't control affiliates. NBC documented multiple affiliates doing this. Congressional hearings have been held. Some states have eliminated the practice. Goodwill lobbied to keep it. The thrift stores generate $6 billion a year from goods people donated for the tax deduction."}});

w('profiles_v14','american-red-cross',{"brand_name":"American Red Cross","brand_slug":"american-red-cross","parent_company":"American National Red Cross","ultimate_parent":"American National Red Cross","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"THE RED CROSS RAISED $500 MILLION FOR HAITI EARTHQUAKE RELIEF AND BUILT SIX HOUSES — A PROPUBLICA/NPR INVESTIGATION DOCUMENTED WHERE THE MONEY WENT — NOBODY COULD FULLY EXPLAIN IT","executive_summary":"The American Red Cross is the United States' primary disaster relief organization, operating under a congressional charter and raising approximately $3 billion annually. A 2015 ProPublica and NPR joint investigation — one of the most significant pieces of nonprofit accountability journalism in recent decades — documented that the Red Cross had raised approximately $500 million for Haiti earthquake relief (2010) but had built only six permanent homes, failed to provide promised services to hundreds of thousands of Haitians, and was unable to account for how it had spent the money. Internal Red Cross documents obtained by ProPublica showed executives were aware of significant operational failures. The investigation also documented that the Red Cross had diverted ambulances from Sandy storm relief in New Jersey to serve as backdrops for a public relations event. The Red Cross maintained it had provided significant Haiti relief beyond housing and disputed some specific findings.","verdict_tags":["haiti_500m_raised_6_houses_built","propublica_npr_2015_investigation_pulitzer","sandy_ambulances_pr_event_diversion","ceo_gail_mcgovern_salary_600k","blood_supply_monopoly_revenue","internal_documents_showed_operational_failures","congressional_charter_public_trust","3b_annual_revenue"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":true,"legal":false},"labor":{"summary":"The Red Cross employs approximately 22,000 paid staff and mobilizes approximately 300,000 volunteers. No major documented systemic labor violations have been identified at the organizational level.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against the Red Cross have been identified.","flags":[],"sources":[]},"political":{"summary":"The American Red Cross was chartered by Congress in 1905 and has operated under that charter ever since — giving it a unique quasi-governmental status. The President of the United States is the honorary chairman of the Red Cross. This status creates a documented accountability gap: the Red Cross is neither fully government (subject to Congressional oversight and FOIA) nor fully private (no standard nonprofit accountability applies). Its blood supply operations — which provide approximately 40% of the US blood supply — operate as a near-monopoly with significant pricing power.","flags":["congressional_charter_quasi_governmental","president_honorary_chairman","blood_supply_40pct_us_monopoly","accountability_gap_neither_government_nor_private"],"sources":[]},"legal":{"summary":"In 2003, the Red Cross reached a $5.2 billion settlement with the FDA over blood safety violations — the largest civil settlement with a nonprofit at the time — covering systematic failures in blood collection and processing that put donors and patients at risk. The Red Cross's blood operations had been subject to FDA oversight and enforcement for decades. The Haiti investigation generated Congressional hearings; no criminal charges were filed. The Sandy ambulance diversion was documented but not prosecuted.","flags":["5_2b_fda_blood_safety_settlement_2003","blood_collection_processing_failures","congressional_hearings_haiti_no_charges","sandy_ambulance_diversion_documented"],"sources":["https://www.propublica.org/article/how-the-red-cross-raised-half-a-billion-dollars-for-haiti-and-built-6-homes"]},"tax":{"summary":"The American Red Cross is a 501(c)(3) public charity — donations are tax-deductible. It files Form 990. Its annual revenue of approximately $3 billion includes public donations, government grants, and blood supply revenue. CEO Gail McGovern's compensation was approximately $600,000 annually during the Haiti period. The blood supply revenue — from selling blood products to hospitals — operates as a for-profit business within a nonprofit framework, generating significant revenue.","flags":["form_990_public","mcgovern_600k_compensation","blood_revenue_for_profit_within_nonprofit","3b_annual_revenue"],"sources":[]},"executives":{"summary":"Gail McGovern served as Red Cross CEO from 2008 to 2023 — spanning the Haiti earthquake response and the ProPublica/NPR investigation. Internal Red Cross documents obtained by ProPublica showed executives were aware of operational failures in Haiti during her tenure. Bonnie McElveen-Hunter served as Board Chair. The Board's accountability for the Haiti failures was a subject of Congressional attention.","flags":["mcgovern_ceo_2008_2023_haiti_period","internal_documents_executive_awareness_documented","mcelveen_hunter_board_chair","congressional_board_accountability_attention"],"sources":["https://www.propublica.org/article/how-the-red-cross-raised-half-a-billion-dollars-for-haiti-and-built-6-homes"]},"connections":{"summary":"The Red Cross's congressional charter gives it official standing in US disaster response that no other nonprofit has — FEMA and other federal agencies coordinate directly with the Red Cross. This official standing creates both unique access and unique accountability expectations. The blood supply monopoly — where the Red Cross provides approximately 40% of the US blood supply — creates a documented revenue stream funded by hospitals and ultimately by patients.","flags":["fema_official_coordination","blood_supply_hospital_patient_revenue_stream"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"ProPublica and NPR's investigation alleged that the Red Cross's internal management culture — which prioritized public image and fundraising over operational effectiveness — was a systemic cause of the Haiti failures, not merely isolated operational mistakes. Internal documents showed executives discussing how to manage the PR implications of failures rather than how to fix the failures. The Red Cross disputed characterizations of its Haiti response while acknowledging specific operational failures.","flags":["image_fundraising_prioritized_operational_effectiveness_alleged","internal_documents_pr_management_over_fixing","red_cross_disputed_while_acknowledging_specific_failures"],"sources":["https://www.propublica.org/article/how-the-red-cross-raised-half-a-billion-dollars-for-haiti-and-built-6-homes"]},"health_record":{"summary":"The FDA's 2003 blood safety enforcement action against the Red Cross — including the $5.2 billion settlement — documented systematic failures in blood collection and processing that created health risks for blood donors and recipients. The Haiti response failures — where $500 million raised for earthquake victims produced six permanent homes — represent documented failures to provide promised health and humanitarian services to hundreds of thousands of earthquake survivors.","flags":["blood_safety_violations_donor_recipient_risk","fda_enforcement_systematic_failures","haiti_promised_services_not_delivered_documented"],"sources":["https://www.propublica.org/article/how-the-red-cross-raised-half-a-billion-dollars-for-haiti-and-built-6-homes"]},"alternatives":{"cheaper":["Direct Relief — highly rated disaster relief organization with documented operational efficiency","International Rescue Committee — secular humanitarian with documented effectiveness","Doctors Without Borders (MSF) — direct medical intervention"],"healthier":["Partners in Health — Haiti-focused health organization with documented decade-long Haiti presence and community trust","Direct Relief — 99% charity rating from Charity Navigator"],"diy":["The ProPublica/NPR Haiti investigation is publicly available — read before donating after disasters","Charity Navigator and GiveWell rate disaster relief organizations on financial efficiency and effectiveness"]},"timeline":[{"year":1903,"event":"Congressional charter enacted; Red Cross given official disaster relief role","severity":"neutral","source_url":""},{"year":2003,"event":"$5.2B FDA blood safety settlement — largest civil nonprofit settlement at time; systematic blood collection failures documented","severity":"critical","source_url":""},{"year":2010,"event":"Haiti earthquake; Red Cross raises approximately $500M; launches 'transformative' relief program","severity":"high","source_url":""},{"year":2012,"event":"Superstorm Sandy; Red Cross mobilizes; ambulances later documented diverted to serve as PR event backdrops in New Jersey","severity":"critical","source_url":""},{"year":2015,"event":"ProPublica/NPR investigation publishes: $500M raised, 6 homes built, hundreds of thousands without promised services; internal documents show executive awareness of failures","severity":"critical","source_url":"https://www.propublica.org/article/how-the-red-cross-raised-half-a-billion-dollars-for-haiti-and-built-6-homes"},{"year":2016,"event":"Congressional hearings on Haiti response; Red Cross acknowledges some failures; no criminal charges filed","severity":"high","source_url":""}],"community_impact":{"displacement":"Haitian earthquake survivors — approximately 1.5 million displaced — donated to by Americans trusting that $500 million would rebuild communities. Internal Red Cross documents showed the organization knew it was failing to deliver promised services while maintaining its public fundraising and PR operations.","price_illusion":"Red Cross disaster appeals present as straightforward humanitarian relief — donate and help victims. The Haiti investigation documented that the gap between fundraising presentation and operational delivery was extraordinary: $500 million raised, six permanent homes built, internal awareness of failures managed for PR rather than fixed.","tax_math":"Donors to the Red Cross's Haiti appeal received charitable tax deductions for contributions whose operational effectiveness the Red Cross's own internal documents showed was dramatically below what was publicly communicated. The $500 million in tax-deductible contributions generated six permanent homes and significant undocumented expenditures.","wealth_velocity":"The Red Cross's $3 billion annual revenue is sustained by brand trust built over a century. The Haiti and Sandy revelations damaged but did not end that trust — the organization continues to raise $3 billion annually because disaster fundraising relies on name recognition in crisis moments."},"cost_absorption":{"who_benefited":[{"group":"American Red Cross as institution","how":"$500M in Haiti fundraising; brand maintained through PR management; blood supply monopoly revenue; CEO $600k compensation"}],"who_paid":[{"group":"Haitian earthquake survivors","how":"$500M raised in their name built six permanent homes; promised services not delivered; hundreds of thousands without aid promised"},{"group":"American donors","how":"Contributed $500M based on fundraising claims that organizational documents showed were not matched by operational delivery"}],"the_gap":"The Red Cross raised $500 million for Haiti. They built six houses. ProPublica and NPR documented where the money went. The internal documents showed executives knew they were failing and were managing the PR rather than fixing the operations. At Sandy, they diverted ambulances from relief to use as backdrops for a public relations photo opportunity. They paid $5.2 billion for blood safety violations in 2003. Their CEO made $600,000 a year. They have a congressional charter. The President of the United States is their honorary chairman."}});

w('profiles_v14','boy-scouts-of-america',{"brand_name":"Boy Scouts of America","brand_slug":"boy-scouts-of-america","parent_company":"Boy Scouts of America","ultimate_parent":"Boy Scouts of America National Council","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"THE BOY SCOUTS KEPT SECRET FILES ON SEXUAL PREDATORS FOR 70 YEARS — CALLED THEM 'PERVERSION FILES' — AND PAID $850 MILLION TO 82,000 ABUSE SURVIVORS IN THE LARGEST YOUTH ORGANIZATION ABUSE SETTLEMENT IN US HISTORY","executive_summary":"The Boy Scouts of America (BSA) is one of the largest youth organizations in the United States, with approximately 1 million current Scouts and a century-long history. In February 2020, the BSA filed for Chapter 11 bankruptcy — driven by the overwhelming volume of sexual abuse claims from survivors. The bankruptcy process revealed that the BSA had maintained internal files on suspected and known sexual predators since the 1920s — files it called 'perversion files' internally — that were never shared with law enforcement. By the time the bankruptcy concluded, approximately 82,000 survivors had filed claims. In September 2023, the BSA's reorganization plan was confirmed, providing approximately $850 million in settlements — the largest settlement for sexual abuse in any youth-serving organization in US history. The bankruptcy also revealed that the BSA had concealed the perversion files from parents, law enforcement, and the public for approximately 70 years.","verdict_tags":["82000_survivors_largest_youth_organization_abuse","850m_settlement_largest_youth_organization","perversion_files_70_years_concealed","chapter_11_2020_abuse_claims_driven","perversion_files_never_shared_law_enforcement","local_councils_asset_separate_bankruptcy","chartered_organizations_co_defendants","1_million_current_scouts"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":true,"legal":true},"labor":{"summary":"The BSA employs professional Scouters at national, regional, and local levels alongside its vast volunteer leadership structure. No major documented systemic labor violations have been identified beyond the abuse cover-up.","flags":[],"sources":[]},"environmental":{"summary":"The BSA has documented environmental stewardship programs — conservation and outdoor ethics are core program elements. No major environmental enforcement actions have been identified.","flags":[],"sources":[]},"political":{"summary":"The BSA excluded openly gay Scouts until 2013 and openly gay leaders until 2015 — positions that generated sustained legal and civil rights challenges. It excluded transgender Scouts until 2017. The organization's chartered relationships with religious organizations — particularly the Mormon Church (which was a major BSA sponsor until it withdrew in 2020) — shaped its social positions. The BSA's political evolution on LGBTQ inclusion tracked broader social change but lagged significantly behind public opinion.","flags":["gay_scouts_excluded_until_2013","gay_leaders_excluded_until_2015","transgender_excluded_until_2017","lds_church_major_sponsor_withdrew_2020","lgbtq_inclusion_lagged_public_opinion"],"sources":[]},"legal":{"summary":"February 2020: BSA files for Chapter 11 bankruptcy. The bankruptcy process: local BSA councils filed separately, preserving their assets outside the national bankruptcy estate. Chartered organizations (churches, civic groups that sponsor troops) were separately named in abuse claims and were required to contribute to the settlement fund. September 2023: Reorganization plan confirmed; approximately $850 million settlement covering approximately 82,000 survivor claims. The perversion files: the BSA had maintained files on known and suspected sexual predators since the 1920s — never shared with law enforcement or parents. These files were ordered released by an Oregon court in 2012; they documented abuse patterns the organization had been aware of for decades.","flags":["chapter_11_2020","82000_survivors","850m_settlement","perversion_files_released_oregon_2012","local_councils_separate_estate","chartered_organizations_required_contribution"],"sources":["https://www.nbcnews.com/news/us-news/boy-scouts-bankruptcy-plan-confirmed-82-000-sexual-abuse-survivors-rcna100988"]},"tax":{"summary":"The BSA is a 501(c)(3) public charity — donations are tax-deductible. Local BSA councils are separately incorporated 501(c)(3) entities. The BSA's bankruptcy structure — separating national and local council assets — has been criticized by survivor advocates as allowing the organization to preserve local council assets while limiting national settlement. Chartered organizations' required contributions were primarily from religious institutions, including Catholic dioceses, that had separately been managing abuse claims.","flags":["501c3_national_local_separate","local_council_asset_preservation","chartered_organizations_primarily_religious","catholic_dioceses_among_contributors"],"sources":[]},"executives":{"summary":"Roger Mosby served as BSA CEO during the bankruptcy period. The BSA's national leadership — across multiple CEO tenures — was aware of the perversion files' existence but did not disclose them to law enforcement. The release of the files in 2012 — ordered by an Oregon court in civil litigation — revealed the scope of what the organization had known. The BSA's post-bankruptcy leadership has undertaken significant reforms.","flags":["mosby_ceo_bankruptcy_period","leadership_aware_perversion_files_no_disclosure","2012_court_ordered_release","post_bankruptcy_reforms"],"sources":[]},"connections":{"summary":"The BSA's chartered organization model — where troops are sponsored by religious congregations, civic groups, and other organizations — distributed both the Scouting program and potential abuse liability across thousands of institutions. The Mormon Church was the BSA's largest chartered organization until it withdrew in 2020. Catholic dioceses were among the largest remaining chartered organizations and were required to contribute to the settlement fund.","flags":["lds_largest_withdrew_2020","catholic_dioceses_required_contribution","chartered_model_distributed_liability","thousands_of_chartered_organizations"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Survivors and their attorneys have alleged that BSA executives knowingly used the perversion files to prevent law enforcement from prosecuting known abusers — that the file system was designed as an internal management tool to quietly remove abusers while protecting the organization from scandal rather than protecting future children from known predators. The BSA has disputed the characterization of intent while acknowledging the files' existence and its failure to share them with law enforcement.","flags":["files_designed_prevent_prosecution_alleged","internal_management_protect_organization_not_children_alleged","bsa_disputes_intent_acknowledges_failure"],"sources":[]},"health_record":{"summary":"Approximately 82,000 survivors filed claims in the BSA bankruptcy — the largest documented youth organization abuse claim process in US history. The perversion files documented abuse patterns the BSA was aware of since the 1920s — approximately 70 years before their court-ordered release. Survivors have documented lasting psychological harm from childhood sexual abuse in a trusted youth organization context.","flags":["82000_survivors_largest_youth_organization","70_years_concealed_known_patterns","lasting_psychological_harm_documented"],"sources":["https://www.nbcnews.com/news/us-news/boy-scouts-bankruptcy-plan-confirmed-82-000-sexual-abuse-survivors-rcna100988"]},"alternatives":{"cheaper":["4-H — youth development organization through the US Department of Agriculture","Girls Scouts of the USA — separate organization with different history and documented commitment to inclusion","Campfire — co-ed youth organization"],"healthier":["Youth organizations with published safeguarding policies and mandatory external reporting protocols","Organizations that have never used internal files to manage known abusers without law enforcement involvement"],"diy":["The released BSA perversion files are available through journalistic archives","The bankruptcy court documents — including survivor declarations — are public court records"]},"timeline":[{"year":1910,"event":"Boy Scouts of America founded","severity":"neutral","source_url":""},{"year":1920,"event":"BSA begins maintaining internal files on suspected sexual predators — later called 'perversion files'","severity":"critical","source_url":""},{"year":2012,"event":"Oregon court orders BSA to release perversion files in civil litigation; files document 70 years of known abuse patterns never shared with law enforcement","severity":"critical","source_url":""},{"year":2013,"event":"BSA votes to admit openly gay Scouts; gay leaders remain excluded until 2015","severity":"high","source_url":""},{"year":2020,"event":"February: BSA files for Chapter 11 bankruptcy; LDS Church simultaneously withdraws as largest chartered organization","severity":"critical","source_url":""},{"year":2023,"event":"September: $850M settlement confirmed for approximately 82,000 survivors — largest youth organization abuse settlement in US history","severity":"critical","source_url":"https://www.nbcnews.com/news/us-news/boy-scouts-bankruptcy-plan-confirmed-82-000-sexual-abuse-survivors-rcna100988"}],"community_impact":{"displacement":"82,000 Americans who were abused as Scouts — in the context of a trusted youth development organization — have received settlements averaging approximately $10,000 each from the $850 million fund, which survivor advocates characterized as dramatically insufficient relative to documented harm.","price_illusion":"The BSA presented itself as a character-building organization focused on trustworthiness, loyalty, and duty — the Scout Law's core values. It simultaneously maintained files on known sexual predators for 70 years without sharing them with law enforcement, enabling documented reoffending in new troops.","tax_math":"The BSA and local councils operated as tax-exempt organizations during the 70-year period documented in the perversion files. The $850 million settlement was funded partly through bankruptcy proceedings and partly through chartered organizations' required contributions — with tax implications for all parties.","wealth_velocity":"The BSA's bankruptcy preserved significant local council assets outside the national estate — a structure that survivor advocates argued was specifically designed to minimize settlement payments while maintaining organizational continuity. Local council property and endowments remained available to the continuing organization after settlement."},"cost_absorption":{"who_benefited":[{"group":"Boy Scouts of America as institution","how":"70 years of maintaining perversion files internally rather than reporting to law enforcement preserved organizational reputation while enabling serial reoffending; bankruptcy structure preserved local council assets"},{"group":"Known abusers identified in perversion files","how":"Removed from one troop without law enforcement involvement; documented as reoffending in subsequent placements"}],"who_paid":[{"group":"82,000 sexual abuse survivors","how":"Childhood sexual abuse in trusted youth organization; 70 years of organizational knowledge of patterns without law enforcement disclosure; $850M settlement averaging approximately $10,000 per survivor"}],"the_gap":"The Boy Scouts kept files on sexual predators since the 1920s. They called them perversion files. They never showed them to law enforcement. When a court ordered them released in 2012 they documented 70 years of known abuse patterns. 82,000 survivors filed claims in the bankruptcy. The settlement was $850 million. The average payment was approximately $10,000. The local councils kept their assets. The organization still exists."}});

w('profiles_v14','united-way',{"brand_name":"United Way","brand_slug":"united-way","parent_company":"United Way Worldwide","ultimate_parent":"United Way Worldwide","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"UNITED WAY'S PRESIDENT WILLIAM ARAMONY WAS CONVICTED OF FRAUD — HE SPENT DONOR MONEY ON HIS TEENAGE GIRLFRIEND AND A PRIVATE JET — AND THE CURRENT CEO MAKES $1.6 MILLION FROM AN ORGANIZATION THAT PASSES THROUGH DONOR DOLLARS","executive_summary":"United Way is one of the most recognized charitable brands in America — the annual United Way workplace campaign has been a fixture of American corporate life for decades. United Way Worldwide and its approximately 1,700 local affiliates collectively raise approximately $3.7 billion annually. In 1992, United Way's longtime President and CEO William Aramony was forced to resign after revelations that he had used donor funds for personal expenses including a teenage girlfriend, a private apartment for her, private jet travel, and other personal expenditures. Aramony was subsequently convicted of 25 counts of fraud and sentenced to seven years in prison. The scandal — one of the most significant in nonprofit history — prompted significant changes in nonprofit governance and transparency standards. Current United Way Worldwide CEO Angela Williams's compensation is approximately $1.6 million annually.","verdict_tags":["aramony_convicted_25_counts_fraud_sentenced_7_years","teenage_girlfriend_donor_funds","1_6m_current_ceo_compensation","3_7b_annual_fundraising","1700_local_affiliates","workplace_campaign_corporate_fixture","passthrough_allocation_model_criticized","aramony_1992_resignation_scandal"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":false,"legal":true},"labor":{"summary":"United Way Worldwide and its local affiliates employ thousands of staff across fundraising, allocation, and program operations. No major documented systemic labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for United Way.","flags":[],"sources":[]},"political":{"summary":"United Way's primary political activity is advocacy for its funding recipients — social services organizations receiving United Way allocation. The organization has adopted a focus area strategy (Education, Income, Health) that guides its advocacy positions. No major documented controversial political activities have been identified beyond the allocation debates.","flags":["education_income_health_focus_areas","recipient_advocacy_primary_political_activity"],"sources":[]},"legal":{"summary":"William Aramony: United Way's president and CEO from 1970 to 1992 was forced to resign after the Washington Post documented that he had spent donor funds on personal expenses including supporting a teenage girlfriend, an apartment, private jet travel, and other personal expenditures. Aramony was convicted of 25 counts of fraud and conspiracy, sentenced to seven years in prison, and served five years. The scandal prompted congressional scrutiny of nonprofit governance and voluntary adoption of transparency standards across the sector. No major criminal enforcement actions against United Way Worldwide have been identified since the Aramony case.","flags":["aramony_25_counts_fraud_7_year_sentence_served_5","teenage_girlfriend_apartment_jet_documented","congressional_scrutiny_sector_reform","no_major_criminal_since_aramony"],"sources":[]},"tax":{"summary":"United Way Worldwide and its local affiliates are 501(c)(3) public charities — donations are tax-deductible. Angela Williams's $1.6 million compensation is disclosed through Form 990. The United Way's allocation model — receiving donations through workplace campaigns and distributing to local nonprofits — generates significant overhead in the fundraising and allocation process. Critics of the United Way model argue that donors can give more efficiently directly to specific organizations they want to support.","flags":["form_990_public","williams_1_6m_disclosed","workplace_campaign_overhead","direct_giving_efficiency_critique"],"sources":[]},"executives":{"summary":"Angela Williams serves as CEO of United Way Worldwide with compensation of approximately $1.6 million annually — disclosed through Form 990. William Aramony served from 1970 to 1992 and built United Way into its dominant position in American workplace giving through a combination of corporate partnerships and aggressive fundraising — and used donor funds for personal benefit throughout his later tenure. The Aramony scandal and conviction represents the most significant leadership crisis in United Way's history.","flags":["williams_1_6m_ceo","aramony_1970_1992_built_dominance_abused_position","aramony_conviction_most_significant_crisis"],"sources":[]},"connections":{"summary":"United Way's workplace campaign model — where employers encourage employees to donate through payroll deduction to United Way — has been the dominant workplace charitable giving vehicle for decades. This model gives United Way significant power over which local nonprofits receive funding through its allocation process. Organizations that are not United Way recipients may struggle for workplace donation access in companies where United Way is the designated giving vehicle. The model has been disrupted by workplace giving platforms that allow employees to give directly to any nonprofit.","flags":["workplace_campaign_dominant_vehicle","allocation_power_local_nonprofits","platforms_disrupting_model","payroll_deduction_capture"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Critics of the United Way model have alleged that its workplace campaign dominance effectively crowds out other nonprofits from workplace giving, giving United Way significant power to determine which organizations receive funding based on criteria that are not always transparent. Individual United Way affiliates have been criticized for allocation processes that favor established, larger organizations over newer and smaller nonprofits serving emerging community needs.","flags":["workplace_crowding_out_alleged","allocation_favors_established_organizations_alleged","transparency_allocation_process_criticized"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against United Way have been identified. Its funding of health-focused social services organizations has documented community health benefits. The Aramony scandal's primary harm was to donor trust and the broader nonprofit sector's credibility.","flags":["health_social_services_funding_documented","aramony_scandal_donor_trust_harm"],"sources":[]},"alternatives":{"cheaper":["Direct giving to specific organizations — eliminates United Way overhead","GiveDirectly — direct cash transfers to individuals in poverty","Local Community Foundations — direct allocation to vetted local nonprofits"],"healthier":["Charity Navigator, GiveWell, and Giving What We Can provide evidence-based direct giving guidance","Donor-advised funds at community foundations for tax-advantaged flexible giving"],"diy":["United Way Worldwide's Form 990 is publicly available","Local United Way affiliate Form 990s are available at ProPublica Nonprofit Explorer","Workplace giving platforms now allow payroll deduction giving to any 501(c)(3)"]},"timeline":[{"year":1887,"event":"United Way founded in Denver, Colorado","severity":"neutral","source_url":""},{"year":1970,"event":"William Aramony becomes United Way president; builds dominant workplace giving position over 22-year tenure","severity":"neutral","source_url":""},{"year":1992,"event":"Washington Post investigation reveals Aramony's misuse of donor funds; he resigns; subsequent investigation and conviction","severity":"critical","source_url":""},{"year":1995,"event":"Aramony convicted of 25 counts of fraud and conspiracy; sentenced to 7 years; serves 5","severity":"critical","source_url":""},{"year":2000,"event":"United Way rebrands and restructures following scandal; adopts focus area strategy","severity":"neutral","source_url":""},{"year":2022,"event":"Angela Williams becomes CEO; compensation disclosed at approximately $1.6M through Form 990","severity":"moderate","source_url":""}],"community_impact":{"displacement":"Local nonprofits that are not United Way recipients may face reduced access to workplace charitable giving in companies where United Way is the primary or exclusive vehicle. The allocation process — controlled by local United Way boards — determines which community organizations receive access to this giving stream.","price_illusion":"United Way workplace campaigns present donation as directly helping community needs. The overhead involved in United Way's fundraising, allocation, and administrative operations means a portion of each donation funds those functions rather than direct services. The Aramony scandal established that this overhead had, in one documented case, included a president's personal expenses.","tax_math":"United Way's allocation model receives tax-deductible donations through workplace payroll deduction and distributes to recipient nonprofits — generating a second layer of charitable tax benefit when recipients receive the funds. Aramony's fraudulent use of donor funds — for personal benefit rather than charitable purposes — represented a documented abuse of the tax-exempt framework.","wealth_velocity":"United Way Worldwide's CEO compensation of $1.6 million annually is drawn from an organization that functions primarily as a fundraising and allocation intermediary. The overhead model concentrates some value in the intermediary rather than in direct services."},"cost_absorption":{"who_benefited":[{"group":"William Aramony","how":"22 years of donor-funded personal expenses including teenage girlfriend, apartment, private jets; sentenced 7 years, served 5"}],"who_paid":[{"group":"United Way donors","how":"Charitable contributions used for president's personal expenses for years before discovery; donor trust in nonprofit sector broadly damaged by scandal"},{"group":"Community nonprofits dependent on United Way allocation","how":"Scandal reduced United Way fundraising and credibility, reducing funds available for allocation to community organizations"}],"the_gap":"William Aramony ran United Way for 22 years. He was using donor money to support a teenage girlfriend — apartment, private jets, personal expenses. The Washington Post found out. He resigned. He was convicted of 25 counts of fraud. He served 5 of his 7 years. The current CEO makes $1.6 million a year. United Way raises $3.7 billion annually. The workplace campaign model controls which local nonprofits get access to payroll deduction giving. That is a lot of power for an organization that was run as a personal expense account for two decades."}});

w('profiles_v14','susan-g-komen',{"brand_name":"Susan G. Komen","brand_slug":"susan-g-komen","parent_company":"Susan G. Komen","ultimate_parent":"Susan G. Komen Board of Directors","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"KOMEN LICENSED ITS PINK RIBBON TO COMPANIES SELLING PRODUCTS WITH CANCER-CAUSING INGREDIENTS — THEN CUT PLANNED PARENTHOOD FUNDING FOR A YEAR IN A POLITICAL DECISION — AND ITS CEO MADE $684,000 FROM A BREAST CANCER CHARITY","executive_summary":"Susan G. Komen is the world's largest breast cancer organization, raising approximately $350 million annually and having raised over $2 billion for breast cancer research and awareness since its founding in 1982. The organization pioneered the pink ribbon — now the world's most recognized cause marketing symbol — and generates significant revenue through licensing the ribbon to corporate partners. Critics have documented 'pinkwashing' — companies using Komen's pink ribbon while selling products associated with cancer risk, including cosmetics with potentially harmful ingredients and processed foods. In 2012, Komen defunded Planned Parenthood's breast cancer screening programs in a decision its leadership initially attributed to a new grant policy — then reversed after massive public backlash. The reversal was accompanied by the resignation of senior vice president Karen Handel, who had championed the defunding. Founder Nancy Brinker's compensation exceeded $684,000 annually.","verdict_tags":["planned_parenthood_defunding_2012_reversed","pinkwashing_cancer_causing_products","nancy_brinker_684k_compensation","pink_ribbon_licensed_harmful_companies","2b_raised_research_awareness_ratio_criticized","handel_resigned_defunding_champion","cure_vs_awareness_spending_ratio","ambassador_appointment_bush_administration"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":false},"labor":{"summary":"Komen employs approximately 600 staff nationally and at its affiliates. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"Komen's pinkwashing issue has direct environmental and health intersections — the pink ribbon has been licensed to companies selling products with potentially carcinogenic ingredients, creating a documented irony of a cancer charity partnering with companies whose products may increase cancer risk.","flags":["pinkwashing_carcinogenic_ingredients_documented"],"sources":[]},"political":{"summary":"The 2012 Planned Parenthood defunding decision — which Komen's leadership initially attributed to a new policy prohibiting grants to organizations under government investigation (Planned Parenthood was under a Congressional inquiry) — was documented by journalists as a political decision championed by Karen Handel, a senior vice president who had run for Georgia governor on an anti-Planned Parenthood platform. The decision and reversal generated the largest-single-week fundraising spike in Planned Parenthood's history. Nancy Brinker — the founder — had been appointed by President George W. Bush as US Ambassador to Hungary and Chief of Protocol of the United States, creating documented connections between Komen's leadership and Republican political networks.","flags":["planned_parenthood_defunding_political_decision_documented","handel_anti_planned_parenthood_history","brinker_bush_ambassador_appointment","reversal_planned_parenthood_largest_fundraising_spike"],"sources":["https://www.nytimes.com/2012/02/07/health/komen-foundation-reverses-decision-on-planned-parenthood.html"]},"legal":{"summary":"No major criminal enforcement actions against Komen have been identified. The Planned Parenthood defunding and reversal generated no legal proceedings — it was a governance decision. Pinkwashing: the pink ribbon licensing has not generated legal action but has been the subject of significant advocacy by organizations including Breast Cancer Action (which operates the Think Before You Pink campaign).","flags":["no_criminal_enforcement","pinkwashing_advocacy_not_legal","planned_parenthood_no_legal_proceedings"],"sources":[]},"tax":{"summary":"Komen is a 501(c)(3) public charity — donations are tax-deductible. It files Form 990. Nancy Brinker's compensation of $684,000 annually was disclosed through Form 990 — a figure critics noted as extraordinarily high for a breast cancer charity whose spending ratios on research versus awareness have been questioned. Pink ribbon licensing fees from corporate partners generate additional revenue. The ratio of Komen spending on awareness versus research has been documented as skewed toward awareness.","flags":["form_990_public","brinker_684k_disclosed","awareness_research_spending_ratio_criticized","pink_ribbon_licensing_revenue"],"sources":[]},"executives":{"summary":"Nancy Brinker founded Komen in honor of her sister Susan G. Komen who died of breast cancer in 1980. Brinker led the organization for decades and built it into the world's largest breast cancer charity. Her $684,000 annual compensation — disclosed through Form 990 — was the subject of significant criticism. The 2012 Planned Parenthood decision occurred during her leadership; she announced the reversal personally. Paula Schneider succeeded Brinker as CEO. Karen Handel — whose anti-Planned Parenthood advocacy was documented as the primary driver of the defunding decision — resigned from Komen following the reversal.","flags":["brinker_684k_subject_criticism","handel_resigned_decision_driver","brinker_led_decades_organization_built"],"sources":[]},"connections":{"summary":"Komen's pink ribbon licensing has generated corporate partnerships with dozens of major companies — including, documented by critics, companies selling products with potentially cancer-causing ingredients. The Think Before You Pink campaign (Breast Cancer Action) specifically targets pinkwashing — documenting companies that use the pink ribbon while selling products associated with cancer risk. KFC and Komen's 'Buckets for the Cure' partnership — selling pink buckets of fried chicken — was a particularly documented example of marketing incongruity.","flags":["kfc_buckets_for_cure_pink_chicken_documented","think_before_you_pink_campaign_targets_komen","cancer_causing_ingredients_pink_licensed_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Breast cancer advocacy critics have alleged that Komen's focus on awareness — pink ribbons, walks, corporate partnerships — over research has slowed scientific progress on breast cancer prevention and treatment. The specific allegation is that Komen's marketing model prioritizes activities that generate fundraising over activities that would most effectively address breast cancer. Komen maintains its research funding is significant and its awareness programs save lives through earlier detection.","flags":["awareness_over_research_priorities_alleged","marketing_model_prioritizes_fundraising_alleged","research_funding_significant_earlier_detection_argument"],"sources":[]},"health_record":{"summary":"The pinkwashing issue has direct health dimensions — Komen's pink ribbon has been licensed to companies selling cosmetics with parabens, phthalates, and other ingredients that some researchers associate with cancer risk. The Planned Parenthood defunding — even for one year — affected access to breast cancer screening for lower-income women at Planned Parenthood facilities. Komen maintains its awareness programs have contributed to earlier detection and improved survival rates.","flags":["pink_licensed_parabens_phthalates_carcinogen_concern","planned_parenthood_screening_access_reduced_one_year","awareness_earlier_detection_survival_argument"],"sources":[]},"alternatives":{"cheaper":["Breast Cancer Research Foundation — higher-rated research spending ratio","National Breast Cancer Coalition — advocacy for research funding"],"healthier":["Think Before You Pink donors guide (thinkbeforeyoupink.org) evaluates pink ribbon campaigns","Breast Cancer Action — advocacy without pink ribbon licensing"],"diy":["Charity Navigator rates Komen vs. alternative breast cancer organizations","Think Before You Pink's annual guide documents pinkwashing products before holiday shopping"]},"timeline":[{"year":1982,"event":"Nancy Brinker founds Susan G. Komen in honor of her sister; Race for the Cure begins","severity":"neutral","source_url":""},{"year":1991,"event":"Pink ribbon introduced as breast cancer awareness symbol; becomes most recognized cause marketing symbol globally","severity":"neutral","source_url":""},{"year":2004,"event":"Brinker appointed by Bush as US Ambassador to Hungary; Komen's Republican political connections documented","severity":"moderate","source_url":""},{"year":2011,"event":"Karen Handel joins Komen as SVP; advocates for defunding Planned Parenthood","severity":"high","source_url":""},{"year":2012,"event":"February: Komen defunds Planned Parenthood citing new grant policy; massive backlash including $3M Planned Parenthood fundraising surge; Komen reverses decision within days; Handel resigns","severity":"critical","source_url":"https://www.nytimes.com/2012/02/07/health/komen-foundation-reverses-decision-on-planned-parenthood.html"},{"year":2015,"event":"Brinker's $684k compensation disclosed; organization restructures leadership amid declining fundraising","severity":"high","source_url":""}],"community_impact":{"displacement":"Lower-income women who relied on Planned Parenthood's Komen-funded breast cancer screening — approximately 170,000 per year at the time of the defunding — had access temporarily reduced during the period of the grant suspension. Planned Parenthood's fundraising surge following the controversy ultimately increased its resources.","price_illusion":"The pink ribbon presents as a simple symbol of breast cancer awareness and research support. Komen's licensing of the ribbon to companies selling products with potentially cancer-associated ingredients — combined with an awareness-to-research spending ratio criticized by advocates — represents a documented gap between the symbol's meaning and the organization's practices.","tax_math":"Komen's $350 million annual revenue is received as tax-deductible charitable contributions. Nancy Brinker's $684,000 compensation was paid from those funds. The pink ribbon licensing fees represent additional revenue from corporate partners who receive charitable cause marketing benefits.","wealth_velocity":"The pink ribbon's global recognition generates significant corporate licensing revenue for Komen. The decision to license the ribbon to companies selling processed foods and cosmetics with potentially harmful ingredients creates documented revenue at the potential expense of the brand's core mission."},"cost_absorption":{"who_benefited":[{"group":"Nancy Brinker and Komen leadership","how":"$684k annual compensation building the world's largest breast cancer charity"},{"group":"Corporate pink ribbon partners","how":"Cause marketing benefit from pink ribbon association regardless of product's health profile"}],"who_paid":[{"group":"Lower-income women at Planned Parenthood","how":"Breast cancer screening access temporarily reduced during defunding period"},{"group":"Donors who trust the pink ribbon","how":"Charitable contributions funding awareness over research at a ratio critics document as skewed; pink ribbon licensed to companies selling potentially cancer-associated products"}],"the_gap":"Komen licensed the pink ribbon to KFC for pink buckets of fried chicken. They licensed it to companies selling cosmetics with ingredients some researchers link to cancer risk. In 2012 they defunded Planned Parenthood's breast cancer screening in what their own documents showed was a political decision. They reversed it after a week when Planned Parenthood raised $3 million in backlash. The SVP who championed the defunding resigned. The founder made $684,000 a year. The research-to-awareness spending ratio has been criticized for years."}});

w('profiles_v14','wounded-warrior-project',{"brand_name":"Wounded Warrior Project","brand_slug":"wounded-warrior-project","parent_company":"Wounded Warrior Project","ultimate_parent":"Wounded Warrior Project Board of Directors","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"CBS NEWS DOCUMENTED WOUNDED WARRIOR PROJECT SPENDING $26 MILLION ON CONFERENCES AND MEETINGS IN TWO YEARS — STAFF DESCRIBED 'EXTRAVAGANT' PARTIES — AND THE CEO AND COO WERE FIRED AFTER THE INVESTIGATION","executive_summary":"Wounded Warrior Project (WWP) is a veterans service organization founded in 2003, raising approximately $500 million annually to serve post-9/11 veterans. In January 2016, CBS News published an investigation — based on interviews with more than 40 current and former WWP employees — documenting that the organization had spent approximately $26 million on conferences and meetings in two years, that employees described lavish parties with expensive meals and entertainment, and that WWP's spending on overhead had grown dramatically relative to direct veteran services. Following the investigation, WWP fired CEO Steve Nardizzi and COO Al Giordano. An independent audit commissioned by the board found that conference expenditures had been excessive and inconsistent with the organization's charitable mission. WWP subsequently reformed its spending practices and its Charity Navigator rating has improved.","verdict_tags":["26m_conferences_meetings_two_years","ceo_coo_fired_after_investigation","cbs_news_40_employees_investigation","lavish_parties_documented_former_employees","charity_navigator_rating_decline_recovery","500m_annual_revenue","overhead_spending_dramatic_growth","post_9_11_veterans_service"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":false,"legal":false},"labor":{"summary":"WWP employs approximately 600 staff. Former employees who spoke to CBS News described a workplace culture where questioning leadership's spending decisions was discouraged and employees who raised concerns faced retaliation. The CEO and COO firings followed both the CBS investigation and internal board review.","flags":["retaliation_concern_raising_alleged_former_employees","ceo_coo_fired_post_investigation"],"sources":["https://www.cbsnews.com/news/wounded-warrior-project-accused-of-spending-problems/"]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for WWP.","flags":[],"sources":[]},"political":{"summary":"WWP is a veterans service organization whose mission is politically uncontroversial. It has not engaged in documented political advocacy beyond veterans issues. The CBS investigation's political impact was on the nonprofit accountability landscape — generating significant discussion about overhead ratios and the accountability of large veterans charities.","flags":["veterans_issues_noncontroversial_mission","nonprofit_accountability_landscape_impact"],"sources":[]},"legal":{"summary":"No criminal enforcement actions against WWP have been identified. The CBS investigation, the subsequent board review, and the CEO/COO firing were handled internally. The independent audit commissioned by the board found excessive conference spending but did not identify criminal conduct. WWP has not been charged with any offense.","flags":["no_criminal_enforcement","board_independent_audit_excessive_spending","no_charges"],"sources":[]},"tax":{"summary":"WWP is a 501(c)(3) public charity — donations are tax-deductible. It files Form 990. Steve Nardizzi's compensation prior to his firing was approximately $500,000 annually — disclosed through Form 990. The $26 million in conference spending over two years was received from charitable donations. WWP's overhead ratio — the percentage of spending on administration and fundraising versus direct programs — became the primary accountability metric discussed following the investigation.","flags":["form_990_public","nardizzi_500k_compensation","26m_from_charitable_donations","overhead_ratio_accountability_focus"],"sources":[]},"executives":{"summary":"CEO Steve Nardizzi and COO Al Giordano were fired by WWP's board of directors in March 2016 following the CBS investigation and the board's independent review. Michael Linnington became CEO and undertook significant organizational reforms. The board's decision to fire both executives represented one of the faster nonprofit leadership accountability responses to a major media investigation in the sector's history.","flags":["nardizzi_giordano_fired_march_2016","linnington_reform_ceo","board_faster_accountability_response_sector"],"sources":["https://www.cbsnews.com/news/wounded-warrior-project-accused-of-spending-problems/"]},"connections":{"summary":"WWP's size — $500 million annual revenue — made it the largest veterans service nonprofit in the US by revenue at the time of the investigation. The investigation prompted scrutiny of the broader veterans charity landscape, where multiple organizations were found to have high overhead ratios. The Better Business Bureau and Charity Navigator both updated their WWP assessments following the investigation.","flags":["largest_veterans_nonprofit_revenue","broader_veterans_charity_scrutiny","bbb_charity_navigator_updated_assessments"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former WWP employees quoted in the CBS investigation alleged that the organization's spending culture — lavish conferences, open bars, entertainment — reflected a prioritization of employee perks and leadership comfort over veteran services; and that employees who questioned spending were marginalized or terminated. WWP disputed these characterizations while acknowledging that some conference spending had been excessive.","flags":["spending_culture_perks_over_veterans_alleged","employee_questioning_retaliation_alleged","wwp_disputed_while_acknowledging_excessive"],"sources":["https://www.cbsnews.com/news/wounded-warrior-project-accused-of-spending-problems/"]},"health_record":{"summary":"No direct health enforcement actions against WWP have been identified. The documented concern is financial — whether charitable donations intended to serve veterans with physical and psychological injuries were being spent on overhead and staff entertainment at documented excessive rates.","flags":["financial_overhead_not_health_enforcement"],"sources":[]},"alternatives":{"cheaper":["Disabled American Veterans (DAV) — highly rated veterans service organization","Fisher House Foundation — housing for military families at VA hospitals","Gary Sinise Foundation — veterans services with high program spending ratio"],"healthier":["Veterans service organizations with lower overhead ratios verified by Charity Navigator","Direct VA advocacy — supporting adequate VA funding through policy advocacy"],"diy":["Charity Navigator rates veterans charities including WWP and alternatives","WWP's Form 990 is available at ProPublica Nonprofit Explorer — current overhead ratios are disclosed"]},"timeline":[{"year":2003,"event":"Wounded Warrior Project founded to support post-9/11 veterans","severity":"neutral","source_url":""},{"year":2014,"event":"WWP spends approximately $26M on conferences and meetings over two fiscal years","severity":"critical","source_url":""},{"year":2016,"event":"January: CBS News investigation publishes; 40+ current and former employees document excessive spending and lavish events. March: Board fires CEO Nardizzi and COO Giordano. Independent audit confirms excessive conference spending.","severity":"critical","source_url":"https://www.cbsnews.com/news/wounded-warrior-project-accused-of-spending-problems/"},{"year":2017,"event":"WWP under new CEO Linnington reforms spending; Charity Navigator rating recovers","severity":"moderate","source_url":""}],"community_impact":{"displacement":"Veterans with service-connected injuries and psychological wounds who donated to or sought services from WWP during the period of excessive overhead spending received less in direct services than their contributions would have funded under different spending practices. The CBS investigation's disclosure damaged the broader veterans charity sector's credibility.","price_illusion":"Wounded Warrior Project's marketing — featuring veterans with visible injuries and compelling stories — presented donation as directly funding veteran services. The $26 million in conference spending over two years — with documented lavish events — represented a spending pattern inconsistent with that marketing presentation.","tax_math":"$26 million in charitable donations designated for veterans services were spent on conferences, parties, and overhead during the two-year documented period. All of these donations were received as tax-deductible charitable contributions. Steve Nardizzi's $500,000 compensation was paid from those funds.","wealth_velocity":"WWP's rapid growth — from a small startup to $500 million annually — created the spending culture documented in the CBS investigation. The board's response — firing both executives — was unusually decisive for a large nonprofit."},"cost_absorption":{"who_benefited":[{"group":"WWP leadership and staff under Nardizzi","how":"Lavish conferences, parties, and entertainment funded from charitable donations designated for veterans"},{"group":"Steve Nardizzi and Al Giordano","how":"$500k+ compensation; conference culture they built; fired but not criminally charged"}],"who_paid":[{"group":"Post-9/11 veterans with service-connected injuries","how":"Charitable donations in their name spent on overhead and entertainment rather than direct services"}],"the_gap":"Wounded Warrior Project raised $500 million a year from people who wanted to help veterans. They spent $26 million on conferences and meetings in two years. Former employees described lavish parties. CBS interviewed 40 current and former employees. The CEO and COO were fired. The board commissioned an independent audit. No criminal charges were filed. The organization reformed. The veterans who were supposed to receive those services during those two years received less than the donations would have funded."}});

